// Aggregate cost per agent (role) over the last 24h from Langfuse traces.
const resp = $input.first().json;
const status = resp.statusCode || 0;
if (status !== 200) {
  return [{ json: { skip: false, error: true, reason: `langfuse ${status}`, details: JSON.stringify(resp.body || {}).slice(0, 300) } }];
}

const traces = resp.body?.data || [];
const byRole = {};
let total = 0;
let totalCalls = 0;
for (const t of traces) {
  const role = t.metadata?.agent_role || t.userId || 'unknown';
  const cost = (t.totalCost ?? 0);
  const calls = (t.observations || []).filter(o => o.type === 'GENERATION').length || 1;
  if (!byRole[role]) byRole[role] = { cost: 0, calls: 0 };
  byRole[role].cost += cost;
  byRole[role].calls += calls;
  total += cost;
  totalCalls += calls;
}

const top = Object.entries(byRole)
  .map(([role, v]) => ({ role, ...v }))
  .sort((a, b) => b.cost - a.cost)
  .slice(0, 5);

const fmt = (n) => '$' + n.toFixed(4);
const alertThreshold = 10; // $/day

return [{
  json: {
    skip: false,
    error: false,
    total,
    totalCalls,
    totalFormatted: fmt(total),
    top,
    topFormatted: top.map(t => `${t.role}=${fmt(t.cost)} (${t.calls} calls)`).join(', '),
    exceedsThreshold: total > alertThreshold,
    alertThreshold,
  }
}];
